import numpy as np

def sigmoid(x):
    return 1.0 / (1.0 + np.exp(-x))

def neg_sampling_loss(v_in, v_out_pos, v_out_negs):
    loss = -np.log(sigmoid(np.dot(v_out_pos, v_in)))
    for v_neg in v_out_negs:
        loss -= np.log(sigmoid(-np.dot(v_neg, v_in)))
    return loss

def run_practice():
    v_in = np.array([1.0, 0.0])
    v_pos = np.array([0.0, 0.0])
    v_negs = [np.array([0.0, 0.0])]
    loss = neg_sampling_loss(v_in, v_pos, v_negs)
    assert np.allclose(loss, 1.386294)
    print('[PASS] Neg sampling math verified.')

if __name__ == '__main__':
    run_practice()
